-- County Tax Property Database Import
-- Generated from spreadsheet data

-- Create table if not exists (migration 017)
CREATE TABLE IF NOT EXISTS tax_counties (
  id INT AUTO_INCREMENT PRIMARY KEY,
  county VARCHAR(100) NOT NULL,
  state VARCHAR(10) NOT NULL,
  assessor_url TEXT,
  treasurer_url TEXT,
  login_required TINYINT(1) DEFAULT 0,
  known_costs_fees VARCHAR(255),
  online_portal TINYINT(1) DEFAULT 0,
  notes TEXT,
  created_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP,
  updated_at TIMESTAMP DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
  UNIQUE KEY unique_county_state (county, state)
);

-- Clear existing data for fresh import
TRUNCATE TABLE tax_counties;

